// Nordique Pro — the brand's required PDF-export font (never Quicksand or any
// other substitute). Embedded directly as base64 data URIs rather than linked
// from a font host, since Nordique Pro is a licensed commercial font with no
// public CDN/Google Fonts distribution — the print window has no other way to
// get it. Three weights only (no Regular): Light stands in for body copy,
// Semibold for the brand/section-heading weight, Bold for headings/totals.
const NORDIQUE_LIGHT_B64 = "";
const NORDIQUE_SEMIBOLD_B64 = "";
const NORDIQUE_BOLD_B64 = "";

export const NORDIQUE_FONT_FACE_CSS = `
  @font-face { font-family: 'Nordique Pro'; src: url('data:font/ttf;base64,${NORDIQUE_LIGHT_B64}') format('truetype'); font-weight: 300; font-style: normal; font-display: block; }
  @font-face { font-family: 'Nordique Pro'; src: url('data:font/ttf;base64,${NORDIQUE_SEMIBOLD_B64}') format('truetype'); font-weight: 600; font-style: normal; font-display: block; }
  @font-face { font-family: 'Nordique Pro'; src: url('data:font/ttf;base64,${NORDIQUE_BOLD_B64}') format('truetype'); font-weight: 700; font-style: normal; font-display: block; }
`;
